## src/services/geminiService.ts

```typescript
import { GoogleGenAI, Type } from "@google/genai";
import { Tool, User, ToolCategory, TaskPriority, DivisionType, Task } from "../types";

// Fallback suggestions if AI fails or no key
const FALLBACK_SUGGESTIONS = [
    "Cek email harian",
    "Update laporan mingguan",
    "Koordinasi tim pagi"
];

export const GeminiService = {

    // 1. SMART SUGGESTIONS
    async getSmartSuggestions(user: User, recentTools: Tool[]): Promise<string[]> {
        if (!process.env.API_KEY) return FALLBACK_SUGGESTIONS;
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        try {
            const toolNames = recentTools.map(t => t.name).join(", ");
            const prompt = `
                Peran User: ${user.role}
                Divisi User: ${user.division}
                Tools Terakhir: ${toolNames}

                Berikan 3 saran tugas singkat (maks 5 kata) yang relevan untuk produktivitas kerja dalam bahasa Indonesia.
                Return ONLY a JSON array of strings.
            `;

            const response = await ai.models.generateContent({
                model: 'gemini-2.5-flash',
                contents: prompt,
                config: {
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.ARRAY,
                        items: { type: Type.STRING }
                    }
                }
            });

            const text = response.text;
            if (text) return JSON.parse(text);
            return FALLBACK_SUGGESTIONS;

        } catch (error) {
            console.error("Gemini Suggestions Error:", error);
            return FALLBACK_SUGGESTIONS;
        }
    },

    // 2. CHECK LINK HEALTH
    async checkLinkHealth(url: string): Promise<{ status: 'ok' | 'broken' | 'unknown', reason?: string }> {
         return { status: 'ok' };
    },

    // 3. SMART ADD TOOL
    async generateToolConfig(description: string, divisionName: string): Promise<Partial<Tool>> {
        if (!process.env.API_KEY) {
            return {
                name: description.substring(0, 15) + '...',
                icon: 'Link',
                color: 'bg-blue-500',
                category: ToolCategory.PROJECT
            };
        }
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        try {
             const prompt = `
                Analisis permintaan pembuatan alat kerja untuk divisi "${divisionName}": "${description}".

                Tentukan:
                1. "name" (Nama pendek, Title Case, maks 25 karakter).
                2. "category" (Pilih salah satu: "${ToolCategory.DAILY}", "${ToolCategory.SHARED}", "${ToolCategory.PROJECT}").
                3. "icon" (Nama ikon Lucide React yang cocok, misal: FileText, BarChart, Users, Globe).
                4. "color" (Tailwind CSS bg color class, misal: bg-blue-500, bg-red-600, bg-green-500, bg-purple-500, bg-orange-500).

                Return ONLY a JSON object.
             `;

             const response = await ai.models.generateContent({
                model: 'gemini-2.5-flash',
                contents: prompt,
                config: {
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: {
                            name: { type: Type.STRING },
                            category: { type: Type.STRING },
                            icon: { type: Type.STRING },
                            color: { type: Type.STRING }
                        },
                        required: ["name", "category", "icon", "color"]
                    }
                }
            });

            const text = response.text;
            if (text) {
                const data = JSON.parse(text);
                return {
                    name: data.name,
                    category: data.category as ToolCategory,
                    icon: data.icon,
                    color: data.color
                };
            }
            throw new Error("Empty response");

        } catch (e) {
            console.error(e);
            return { name: "New Tool", icon: "Link", color: "bg-blue-500", category: ToolCategory.PROJECT };
        }
    },

    // 4. TASK ASSISTANT
    async generateTaskDescription(prompt: string): Promise<string> {
        if (!process.env.API_KEY) return prompt;
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        try {
            const aiPrompt = `Ubah input ini menjadi judul tugas profesional (Bahasa Indonesia): "${prompt}"`;
            const response = await ai.models.generateContent({
                model: 'gemini-2.5-flash',
                contents: aiPrompt,
            });
            return response.text?.trim() || prompt;
        } catch (error) {
            return prompt;
        }
    },

    // 5. BULK IMPORT PARSER
    async parseBulkTasks(text: string): Promise<any[]> {
        if (!process.env.API_KEY) {
            console.warn("API Key missing");
            return [];
        }
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        try {
            const systemPrompt = `
            PERAN: Asisten Project Manager Cerdas.
            TUGAS: Ekstrak daftar tugas dari teks input (chat/notulen) menjadi JSON Array.

            ATURAN PENENTUAN DIVISI (divisionId):
            Analisis konteks kalimat untuk memetakan ke salah satu ID ini:
            - 'Direksi' (Manajemen, keputusan, laporan pimpinan)
            - 'Marketing' (Sosmed, iklan, konten, desain, leads)
            - 'Administrasi' (Surat, arsip, data siswa, input)
            - 'Keuangan' (Gaji, invoice, bayar, pajak, anggaran)
            - 'IT Support' (Wifi, server, error, web, aplikasi, laptop)
            - 'Kebersihan & Keamanan' (Satpam, cleaning, parkir, AC, perbaikan fisik)
            - 'Mitra Kampus' (Kerjasama, MoU, event luar)

            *** ATURAN KHUSUS BROADCAST ***
            Jika perintah ditujukan untuk "Semua", "All Team", "Seluruh Divisi", "Pengumuman", "Setiap Tim", atau tidak spesifik divisi:
            MAKA set "divisionId" menjadi: 'BROADCAST'.

            ATURAN PRIORITAS (priority):
            - 'high': Kata kunci 'segera', 'urgent', 'penting', 'rusak', 'deadline', 'hari ini'.
            - 'low': Kata kunci 'santai', 'ide', 'nanti', 'low'.
            - 'medium': Jika tidak ada indikasi waktu mendesak.

            ATURAN JUDUL (title):
            Buat judul singkat, padat, jelas, menggunakan kata kerja aktif (misal: "Perbaiki Wifi", "Rekap Laporan").

            OUTPUT JSON ONLY:
            [{ "title": string, "divisionId": string, "priority": "high"|"medium"|"low", "dueDate": "YYYY-MM-DD" | null }]
            `;

            const response = await ai.models.generateContent({
                model: 'gemini-2.5-flash',
                contents: `Instruction: ${systemPrompt}\n\nInput Text:\n"${text}"`,
                config: {
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                title: { type: Type.STRING },
                                divisionId: { type: Type.STRING },
                                priority: { type: Type.STRING },
                                dueDate: { type: Type.STRING, nullable: true }
                            },
                            required: ["title", "divisionId", "priority"]
                        }
                    }
                }
            });

            const responseText = response.text;
            return JSON.parse(responseText || '[]');

        } catch (error) {
            console.error("Gemini Bulk Parse Error:", error);
            return [];
        }
    },

    // 6. GENERATE SUBTASKS (TASK BREAKDOWN)
    async generateSubtasks(taskTitle: string, taskDesc?: string): Promise<{title: string}[]> {
        if (!process.env.API_KEY) return [];
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        try {
            const prompt = `
                Tugas: "${taskTitle}"
                Konteks Tambahan: "${taskDesc || ''}"

                Pecah tugas ini menjadi 3-6 langkah (sub-tugas) yang konkret, dapat ditindaklanjuti, dan berurutan.
                Bahasa: Indonesia Formal & Profesional.

                Output JSON: [{ "title": string }]
            `;

            const response = await ai.models.generateContent({
                model: 'gemini-2.5-flash',
                contents: prompt,
                config: {
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                title: { type: Type.STRING }
                            },
                            required: ["title"]
                        }
                    }
                }
            });

            const text = response.text;
            return JSON.parse(text || '[]');
        } catch (e) {
            console.error("Gemini Subtasks Error:", e);
            return [];
        }
    },

    // 7. ASK YOUR DATA (RAG-LITE)
    async askData(question: string, contextData: { tasks: Task[], users: User[], announcements: any[] }): Promise<string> {
        if (!process.env.API_KEY) return "AI Key not configured.";
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        try {
            // Simplify context to save tokens
            const tasksContext = contextData.tasks.map(t => 
                `- [${t.isCompleted ? 'SELESAI' : 'PENDING'}] ${t.title} (Div: ${t.targetDivisionId || t.originDivisionId}, Assignee: ${t.assigneeId}, Priority: ${t.priority})`
            ).join('\n');

            const usersContext = contextData.users.map(u => 
                `- ${u.name} (${u.role} - ${u.division})`
            ).join('\n');

            const prompt = `
                Anda adalah Asisten Kantor Pintar "STIS-DU".
                Jawab pertanyaan user berdasarkan data berikut:

                DATA KARYAWAN:
                ${usersContext}

                DAFTAR TUGAS SAAT INI:
                ${tasksContext}

                Pertanyaan User: "${question}"

                Jawab dengan ramah, singkat, dan informatif. Jika data tidak ada, katakan tidak tahu.
            `;

            const response = await ai.models.generateContent({
                model: 'gemini-2.5-flash',
                contents: prompt,
            });

            return response.text || "Maaf, saya tidak bisa menjawab saat ini.";
        } catch (e) {
            return "Terjadi kesalahan koneksi AI.";
        }
    }
};
```

## src/components/TaskDetailView.tsx

```tsx
import React, { useState, useEffect } from 'react';
import { Task, Subtask } from '../types';
import { Icon } from './Icon';
import { UnifiedDataService } from '../services/UnifiedDataService';
import { GeminiService } from '../services/geminiService';

interface TaskDetailViewProps {
    task: Task & { divName?: string, divIcon?: string, divId?: string };
    isOpen: boolean;
    onClose: () => void;
    onToggle: () => void;
    onDelete: () => void;
    onUpdate: (updates: Partial<Task>) => void;
}

export const TaskDetailView: React.FC<TaskDetailViewProps> = ({ task, isOpen, onClose, onToggle, onDelete, onUpdate }) => {
    const [desc, setDesc] = useState(task.description || '');
    const [title, setTitle] = useState(task.title || '');
    const [subtasks, setSubtasks] = useState<Subtask[]>(task.subtasks || []);
    const [newSubtaskTitle, setNewSubtaskTitle] = useState('');
    const [isUploading, setIsUploading] = useState(false);
    const [isGeneratingSubtasks, setIsGeneratingSubtasks] = useState(false);

    useEffect(() => { 
        setDesc(task.description || ''); 
        setTitle(task.title || ''); 
        setSubtasks(task.subtasks || []);
    }, [task.id]);

    // Auto-save wrapper
    const saveChanges = (updates: Partial<Task>) => {
        onUpdate(updates);
    };

    const handleBlur = () => {
        saveChanges({ title, description: desc, subtasks });
    };

    // Subtask Logic
    const addSubtask = (e?: React.FormEvent) => {
        if(e) e.preventDefault();
        if (!newSubtaskTitle.trim()) return;
        const newSub: Subtask = {
            id: `sub_${Date.now()}`,
            title: newSubtaskTitle,
            isCompleted: false
        };
        const updated = [...subtasks, newSub];
        setSubtasks(updated);
        saveChanges({ subtasks: updated });
        setNewSubtaskTitle('');
    };

    const toggleSubtask = (subId: string) => {
        const updated = subtasks.map(s => s.id === subId ? { ...s, isCompleted: !s.isCompleted } : s);
        setSubtasks(updated);
        saveChanges({ subtasks: updated });
    };

    const deleteSubtask = (subId: string) => {
        const updated = subtasks.filter(s => s.id !== subId);
        setSubtasks(updated);
        saveChanges({ subtasks: updated });
    };

    const handleAIBreakdown = async () => {
        setIsGeneratingSubtasks(true);
        try {
            const steps = await GeminiService.generateSubtasks(title, desc);
            const newSubs = steps.map((s, idx) => ({
                id: `ai_sub_${Date.now()}_${idx}`,
                title: s.title,
                isCompleted: false
            }));
            const updated = [...subtasks, ...newSubs];
            setSubtasks(updated);
            saveChanges({ subtasks: updated });
        } catch (e) {
            alert("Gagal membuat sub-tugas.");
        } finally {
            setIsGeneratingSubtasks(false);
        }
    };

    // Attachment Logic
    const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        setIsUploading(true);
        try {
            const url = await UnifiedDataService.uploadAttachment(file);
            if (url) {
                saveChanges({ attachmentUrl: url });
            }
        } catch (error) {
            console.error("Upload error", error);
            alert("Upload gagal.");
        } finally {
            setIsUploading(false);
        }
    };

    const progress = subtasks.length > 0 
        ? Math.round((subtasks.filter(s => s.isCompleted).length / subtasks.length) * 100) 
        : 0;

    return (
        <div className={`absolute inset-y-0 right-0 w-full md:w-[600px] bg-[#0f172a]/95 backdrop-blur-2xl border-l border-white/10 shadow-2xl z-50 transform transition-transform duration-300 ease-in-out flex flex-col ${isOpen ? 'translate-x-0' : 'translate-x-full'}`}>
            <div className="h-16 border-b border-white/5 bg-white/5 flex items-center justify-between px-6 shrink-0">
                <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-lg text-gray-400 hover:text-white transition-colors"><Icon name="X" size={24} /></button>
                <div className="flex items-center gap-2 px-3 py-1.5 bg-black/30 rounded-full border border-white/5"><Icon name={task.divIcon || "CheckSquare"} size={14} className="text-brand-400" /><span className="text-xs font-bold text-gray-300 uppercase tracking-wider">{task.divName || "Task"}</span></div>
            </div>

            <div className="flex-1 overflow-y-auto custom-scrollbar p-8 space-y-8">
                {/* Title & Meta */}
                <div className="space-y-4">
                    <div className="flex items-start gap-3">
                        <button onClick={onToggle} className={`mt-1.5 w-6 h-6 rounded-lg border flex items-center justify-center transition-all shrink-0 ${task.isCompleted ? 'bg-emerald-500 border-emerald-500' : 'border-gray-500 hover:border-brand-400'}`}>{task.isCompleted && <Icon name="Check" size={14} className="text-white" />}</button>
                        <input className="w-full bg-transparent text-2xl font-bold text-white outline-none border-none p-0 focus:ring-0" value={title} onChange={(e) => setTitle(e.target.value)} onBlur={handleBlur} />
                    </div>
                    <div className="flex flex-wrap gap-3 pl-9">
                        <div className={`flex items-center gap-2 px-3 py-1.5 rounded-lg border ${task.priority === 'high' ? 'bg-red-500/10 border-red-500/20 text-red-300' : 'bg-blue-500/10 border-blue-500/20 text-blue-300'}`}><Icon name="Flag" size={14} /><span className="text-xs font-bold uppercase">{task.priority} Priority</span></div>
                        <div className="flex items-center gap-2 px-3 py-1.5 rounded-lg border border-white/5 bg-white/5 text-gray-300"><Icon name="Calendar" size={14} /><span className="text-xs font-medium">{task.dueDate || 'No Due Date'}</span></div>
                        <div className="flex items-center gap-2 px-3 py-1.5 rounded-lg border border-white/5 bg-white/5 text-gray-300"><Icon name="User" size={14} /><span className="text-xs font-medium">{task.assigneeId ? 'Assigned' : 'Unassigned'}</span></div>
                    </div>
                </div>

                {/* CHECKLIST (SUBTASKS) */}
                <div className="h-px bg-white/5 w-full"></div>
                <div className="pl-9 space-y-4">
                    <div className="flex items-center justify-between">
                        <h4 className="text-xs font-bold text-gray-500 uppercase tracking-widest flex items-center gap-2"><Icon name="ListChecks" size={14} /> Langkah Pengerjaan ({progress}%)</h4>
                        <button 
                            onClick={handleAIBreakdown}
                            disabled={isGeneratingSubtasks} 
                            className="text-[10px] flex items-center gap-1 bg-purple-500/10 hover:bg-purple-500/20 text-purple-300 px-2 py-1 rounded-lg transition-colors disabled:opacity-50"
                        >
                            {isGeneratingSubtasks ? <Icon name="Loader2" size={12} className="animate-spin" /> : <Icon name="Sparkles" size={12} />}
                            AI Breakdown
                        </button>
                    </div>

                    {/* Progress Bar */}
                    <div className="h-1.5 w-full bg-white/5 rounded-full overflow-hidden">
                        <div className="h-full bg-brand-500 transition-all duration-500" style={{ width: `${progress}%` }}></div>
                    </div>

                    <div className="space-y-2">
                        {subtasks.map(sub => (
                            <div key={sub.id} className="flex items-center gap-3 group">
                                <button onClick={() => toggleSubtask(sub.id)} className={`w-4 h-4 rounded border flex items-center justify-center transition-colors ${sub.isCompleted ? 'bg-brand-500 border-brand-500' : 'border-gray-600 hover:border-brand-400'}`}>
                                    {sub.isCompleted && <Icon name="Check" size={10} className="text-white" />}
                                </button>
                                <span className={`flex-1 text-sm ${sub.isCompleted ? 'text-gray-500 line-through' : 'text-gray-300'}`}>{sub.title}</span>
                                <button onClick={() => deleteSubtask(sub.id)} className="opacity-0 group-hover:opacity-100 text-gray-500 hover:text-red-400 transition-opacity"><Icon name="X" size={14}/></button>
                            </div>
                        ))}
                    </div>

                    <form onSubmit={addSubtask} className="flex items-center gap-3">
                        <Icon name="Plus" size={16} className="text-gray-500 ml-0.5" />
                        <input 
                            className="flex-1 bg-transparent text-sm text-white placeholder-gray-600 outline-none"
                            placeholder="Tambah langkah baru..."
                            value={newSubtaskTitle}
                            onChange={(e) => setNewSubtaskTitle(e.target.value)}
                        />
                    </form>
                </div>

                {/* ATTACHMENT SECTION */}
                <div className="h-px bg-white/5 w-full"></div>
                <div className="pl-9 space-y-3">
                    <h4 className="text-xs font-bold text-gray-500 uppercase tracking-widest flex items-center gap-2"><Icon name="Paperclip" size={14} /> Lampiran / Dokumen</h4>

                    {task.attachmentUrl ? (
                        <div className="p-4 bg-white/5 rounded-xl border border-white/10 flex items-center justify-between group hover:border-brand-500/50 transition-colors">
                            <div className="flex items-center gap-3 overflow-hidden">
                                <div className="p-2 bg-brand-500/20 text-brand-400 rounded-lg"><Icon name="FileText" size={20} /></div>
                                <div className="min-w-0">
                                    <a href={task.attachmentUrl} target="_blank" rel="noreferrer" className="text-sm font-medium text-white hover:underline truncate block">Lihat Dokumen</a>
                                    <p className="text-[10px] text-gray-500 truncate">{task.attachmentUrl}</p>
                                </div>
                            </div>
                            <button onClick={() => saveChanges({ attachmentUrl: undefined })} className="p-2 text-gray-500 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity"><Icon name="Trash2" size={16}/></button>
                        </div>
                    ) : (
                        <div className="relative">
                            <input 
                                type="file" 
                                onChange={handleFileUpload} 
                                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer disabled:cursor-not-allowed"
                                disabled={isUploading}
                            />
                            <div className={`border-2 border-dashed border-white/10 rounded-xl p-6 flex flex-col items-center justify-center text-gray-500 transition-all ${isUploading ? 'bg-white/5' : 'hover:bg-white/5 hover:border-white/20'}`}>
                                {isUploading ? (
                                    <>
                                        <Icon name="Loader2" size={24} className="animate-spin mb-2 text-brand-400" />
                                        <p className="text-xs font-medium">Mengunggah...</p>
                                    </>
                                ) : (
                                    <>
                                        <Icon name="UploadCloud" size={24} className="mb-2" />
                                        <p className="text-xs font-medium">Klik untuk upload file</p>
                                        <p className="text-[10px] opacity-70 mt-1">PDF, Images (Max 2MB)</p>
                                    </>
                                )}
                            </div>
                        </div>
                    )}
                </div>

                <div className="h-px bg-white/5 w-full"></div>
