import React, { useState } from 'react';
import { Icon } from './Icon';
import { GeminiService } from '../services/geminiService';
import { Task, User, Announcement } from '../types';

interface AIAssistantProps {
    tasks: Task[];
    users: User[];
    announcements: Announcement[];
}

export const AIAssistant: React.FC<AIAssistantProps> = ({ tasks, users, announcements }) => {
    const [isOpen, setIsOpen] = useState(false);
    const [query, setQuery] = useState('');
    const [response, setResponse] = useState('');
    const [isLoading, setIsLoading] = useState(false);

    const handleAsk = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!query.trim()) return;
        setIsLoading(true);
        const answer = await GeminiService.askData(query, { tasks, users, announcements });
        setResponse(answer);
        setIsLoading(false);
    };

    return (
        <div className="fixed bottom-6 right-6 z-[100] flex flex-col items-end pointer-events-none">
            {isOpen && (
                <div className="pointer-events-auto bg-[#1e293b] border border-white/10 shadow-2xl rounded-2xl w-80 mb-4 overflow-hidden animate-[scaleIn_0.2s_ease-out] flex flex-col">
                    <div className="p-4 bg-gradient-to-r from-purple-600 to-indigo-600 text-white flex justify-between items-center">
                        <div className="flex items-center gap-2 font-bold"><Icon name="Sparkles" size={16} /> AI Assistant</div>
                        <button onClick={() => setIsOpen(false)}><Icon name="X" size={16} /></button>
                    </div>
                    <div className="p-4 bg-black/20 min-h-[150px] max-h-[300px] overflow-y-auto text-sm text-gray-200">
                        {!response && !isLoading && <p className="text-gray-500 italic text-center mt-4">Tanya saya tentang data kantor...</p>}
                        {isLoading && <div className="flex justify-center p-4"><Icon name="Loader2" className="animate-spin text-purple-400" /></div>}
                        {response && <div className="whitespace-pre-wrap leading-relaxed">{response}</div>}
                    </div>
                    <form onSubmit={handleAsk} className="p-3 border-t border-white/10 bg-[#0f172a] flex gap-2">
                        <input className="flex-1 bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-xs text-white outline-none focus:border-purple-500" placeholder="Ketik pertanyaan..." value={query} onChange={e => setQuery(e.target.value)} />
                        <button type="submit" disabled={!query || isLoading} className="bg-purple-600 text-white p-2 rounded-lg disabled:opacity-50"><Icon name="Send" size={14} /></button>
                    </form>
                </div>
            )}
            <button onClick={() => setIsOpen(!isOpen)} className="pointer-events-auto w-14 h-14 bg-gradient-to-r from-purple-600 to-indigo-600 rounded-full shadow-lg flex items-center justify-center text-white hover:scale-110 transition-transform ring-4 ring-black/20">
                <Icon name={isOpen ? "MessageSquare" : "Sparkles"} size={24} />
            </button>
        </div>
    );
};
