      const stored = localStorage.getItem(KEYS.HOLIDAYS);
      return stored ? JSON.parse(stored) : [
          { id: 'h1', date: '2023-12-25', name: 'Christmas Day' },
          { id: 'h2', date: '2024-01-01', name: 'New Year' }
      ];
