                        </label>
                    </div>
                </div>

                <button onClick={handleSaveNotifications} className="w-full py-3 bg-brand-600 text-white font-bold rounded-xl shadow-lg">Simpan Konfigurasi</button>
            </div>
        )}

        {/* SYSTEM TAB */}
        {activeTab === 'system' && isSystemAdmin && (
            <div className="max-w-4xl mx-auto animate-[fadeIn_0.3s]">
                <div className="flex gap-2 mb-8 bg-black/30 p-1 rounded-xl w-fit">
                    <button onClick={() => setSystemSubTab('announcements')} className={`px-4 py-2 rounded-lg text-xs font-bold ${systemSubTab === 'announcements' ? 'bg-brand-600 text-white' : 'text-gray-400'}`}>Pengumuman</button>
                    <button onClick={() => setSystemSubTab('attendance')} className={`px-4 py-2 rounded-lg text-xs font-bold ${systemSubTab === 'attendance' ? 'bg-brand-600 text-white' : 'text-gray-400'}`}>Absensi</button>
                    <button onClick={() => setSystemSubTab('backup')} className={`px-4 py-2 rounded-lg text-xs font-bold ${systemSubTab === 'backup' ? 'bg-brand-600 text-white' : 'text-gray-400'}`}>Backup</button>
                </div>
                {systemSubTab === 'announcements' && (<div className="bg-white/5 border border-white/5 rounded-2xl p-6"><h3 className="text-lg font-bold text-white mb-4">Pengumuman Baru</h3><form onSubmit={handleAddAnnouncement} className="space-y-4 mb-8"><input className="w-full bg-black/30 border border-white/10 rounded-lg px-4 py-2 text-white" placeholder="Judul" value={newAnnTitle} onChange={e => setNewAnnTitle(e.target.value)} /><textarea className="w-full bg-black/30 border border-white/10 rounded-lg px-4 py-2 text-white h-24" placeholder="Isi..." value={newAnnContent} onChange={e => setNewAnnContent(e.target.value)} /><button type="submit" className="px-4 py-2 bg-brand-600 text-white rounded-lg font-bold">Posting</button></form><div className="space-y-2">{announcements.map(ann => (<div key={ann.id} className="flex justify-between items-center p-3 bg-black/20 rounded-xl border border-white/5"><div><p className="font-bold text-white">{ann.title}</p><p className="text-xs text-gray-500">{ann.date}</p></div><button onClick={() => handleDeleteAnnouncement(ann.id)} className="text-red-500"><Icon name="Trash2" size={16}/></button></div>))}</div></div>)}
                {systemSubTab === 'attendance' && (<div className="bg-white/5 border border-white/5 rounded-2xl p-6 space-y-6"><div className="grid grid-cols-2 gap-6"><input type="time" className="w-full bg-black/30 border border-white/10 rounded px-3 py-2 text-white" value={editWorkStart} onChange={e => setEditWorkStart(e.target.value)} /><input type="time" className="w-full bg-black/30 border border-white/10 rounded px-3 py-2 text-white" value={editWorkEnd} onChange={e => setEditWorkEnd(e.target.value)} /></div><button onClick={handleSaveAttendanceConfig} className="px-4 py-2 bg-white/10 text-white rounded font-bold">Simpan</button></div>)}
                {systemSubTab === 'backup' && (<div className="space-y-6"><div className="bg-indigo-900/20 border border-indigo-500/30 rounded-2xl p-6"><h3 className="font-bold text-white">Cloud Sync</h3><button onClick={handleCloudSync} disabled={isSyncing} className="mt-4 px-6 py-2 bg-indigo-600 text-white rounded font-bold">{isSyncing ? 'Syncing...' : 'Sync to Cloud'}</button></div><div className="bg-white/5 border border-white/5 rounded-2xl p-6"><h3 className="font-bold text-white">Local Backup</h3><div className="flex gap-4 mt-4"><button onClick={handleExportConfig} className="flex-1 bg-black/30 border border-white/10 p-4 rounded text-white font-bold">Export JSON</button><label className="flex-1 bg-black/30 border border-white/10 p-4 rounded text-white font-bold cursor-pointer text-center"><input type="file" className="hidden" onChange={handleImportConfig} />Import JSON</label></div></div></div>)}
            </div>
        )}
      </div>
      <EmployeeModal isOpen={isEmployeeModalOpen} onClose={() => setIsEmployeeModalOpen(false)} onSave={handleSaveEmployee} initialData={editingEmployee} />
    </div>
  );
};
