            try { await supabase!.from('chat_messages').insert([{ id: msg.id, content: msg.content, sender_id: msg.senderId, sender_name: msg.senderName, channel_id: msg.channelId, timestamp: msg.timestamp }]); } catch (err) { console.warn("DB Msg Error"); }
        }
