            } catch (err) { return StorageService.getChatGroups(); }
        }
        return StorageService.getChatGroups();
    },

    createChatGroup: async (group: ChatGroup) => {
        StorageService.createChatGroup(group);
        if (isSupabaseConfigured()) {
            try { await supabase!.from('chat_groups').insert([{ id: group.id, name: group.name, member_ids: group.memberIds, created_by: group.createdBy, created_at: group.createdAt }]); } catch (err) { console.warn("DB Group Error"); }
        }
    },

    subscribeToUpdates: (onTaskChange: () => void, onMessageInsert: (newMsg: ChatMessage) => void, onGroupChange: () => void) => {
        if (!isSupabaseConfigured()) return null;
        return supabase!.channel('db-realtime')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'tasks' }, () => onTaskChange())
            .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'chat_messages' }, (payload) => { onMessageInsert({ id: payload.new.id, content: payload.new.content, senderId: payload.new.sender_id, senderName: payload.new.sender_name, channelId: payload.new.channel_id, timestamp: payload.new.timestamp }); })
            .on('postgres_changes', { event: '*', schema: 'public', table: 'chat_groups' }, () => onGroupChange())
            .subscribe();
    },

    syncLocalToCloud: async (tasks: Task[], messages: ChatMessage[], groups: ChatGroup[]) => {
        if (!isSupabaseConfigured()) return { success: false, message: 'Supabase client not initialized' };
        try {
            if (tasks.length > 0) {
                const { error } = await supabase!.from('tasks').upsert(tasks.map(t => ({
                    id: t.id, title: t.title, description: t.description, is_completed: t.isCompleted, priority: t.priority, creator_id: t.creatorId, assignee_id: t.assigneeId, origin_division_id: t.originDivisionId, target_division_id: t.targetDivisionId, due_date: t.dueDate, reminder_at: t.reminderAt, is_reminded: t.isReminded, attachment_url: t.attachmentUrl, subtasks: t.subtasks, created_at: new Date(t.timestamp || Date.now()).toISOString()
                })), { onConflict: 'id' });
                if (error) return { success: false, message: `Tasks Sync Failed: ${getErrorMessage(error)}` };
            }
            // ... Sync Messages & Groups logic remains similar ...
            if (messages.length > 0) {
                 await supabase!.from('chat_messages').upsert(messages.map(m => ({ id: m.id, content: m.content, sender_id: m.senderId, sender_name: m.senderName, channel_id: m.channelId, timestamp: m.timestamp })), { onConflict: 'id' });
            }
            if (groups.length > 0) {
                 await supabase!.from('chat_groups').upsert(groups.map(g => ({ id: g.id, name: g.name, member_ids: g.memberIds, created_by: g.createdBy, created_at: g.createdAt })), { onConflict: 'id' });
            }
            return { success: true };
        } catch (e) { return { success: false, message: getErrorMessage(e) }; }
    }
};

