                                        const subtasks = task.subtasks || [];
                                        const completedSub = subtasks.filter(s => s.isCompleted).length;

                                        return (
                                            <div key={task.id} className="min-w-[260px] w-[260px] snap-start" onClick={() => handleTaskClick(task)}>
