export const Dashboard: React.FC<DashboardProps> = ({ 
    tools, user, handleToolClick, onContextMenu, onSelect, onAddTool, setNotification, isSelectionMode, selectedIds, 
    setSmartAddContext, onOpenAttendance, onOpenProfile, lang, todayAttendance, unreadAnnouncements, 
    announcements, messages, onSendMessage, activeChannel, onChangeChannel,
    dashboardDivisions, onAddTask, onToggleTask, onDeleteTask, tasks, onUpdateTask, groups
}) => {
    const navigate = useNavigate(); 
    const t = translations[lang] || translations.en; 
    const [searchTerm, setSearchTerm] = useState('');
    const [isPanelOpen, setIsPanelOpen] = useState(false);
    const [panelTab, setPanelTab] = useState<'tasks' | 'discussion'>('tasks');
    const [dashboardView, setDashboardView] = useState<'grid' | 'kanban'>('grid');
    const [selectedTask, setSelectedTask] = useState<(Task & { divName?: string, divIcon?: string, description?: string, divId?: string }) | null>(null);

    const prefs = StorageService.getPreferences();

    const openPanel = (tab: 'tasks' | 'discussion') => { setPanelTab(tab); setIsPanelOpen(true); };
    const hasEditPermission = (divId: DivisionType) => user.role === UserRole.ADMIN || (user.role === UserRole.MANAGER && user.division === divId);

    const displayedDivisions = useMemo(() => user.role === UserRole.ADMIN ? dashboardDivisions : dashboardDivisions.filter(d => d.id === user.division), [user, dashboardDivisions]);

    const filteredTools = useMemo(() => { 
        let allowedTools = tools;
        if (user.role !== UserRole.ADMIN) { allowedTools = tools.filter(t => t.divisionId === user.division || !t.divisionId); }
        if (!searchTerm) return allowedTools;
        return allowedTools.filter((t: Tool) => t.name.toLowerCase().includes(searchTerm.toLowerCase()) || t.category.toLowerCase().includes(searchTerm.toLowerCase())); 
    }, [tools, searchTerm, user]);

    const handleMirrorTool = (toolId: string, targetDivisionId: string) => { 
        const originalTool = tools.find((t: Tool) => t.id === toolId); 
        if (!originalTool) return; 
        if (originalTool.divisionId === targetDivisionId) { setNotification("Already in this division"); return; } 
        onAddTool({ ...originalTool, id: `t_${Date.now()}_mirror`, divisionId: targetDivisionId as DivisionType, lastAccessed: 0, isLocked: false }); 
        setNotification(`Mirrored to ${targetDivisionId}`); 
    };

    const handleWhatsApp = (task: Task) => NotificationService.sendToWhatsApp(task, prefs);
    const handleQuickAddTask = (divId: DivisionType) => { const title = prompt("New Task Title:"); if (title) onAddTask(divId, title, 'medium'); };

    const tickerTasks = tasks.filter((t: Task) => (t.priority === 'high' && !t.isCompleted) && (t.assigneeId === user.id || !t.assigneeId || (t.targetDivisionId === user.division && t.originDivisionId !== user.division)));

    const getDivisionTheme = (divId: string) => {
        if (divId.includes('Direksi')) return { bg: 'from-purple-900 to-indigo-900', border: 'border-purple-500/30', iconBg: 'bg-purple-500', text: 'text-purple-100' };
        if (divId.includes('Marketing')) return { bg: 'from-blue-900 to-cyan-900', border: 'border-blue-500/30', iconBg: 'bg-blue-500', text: 'text-blue-100' };
        if (divId.includes('Keuangan')) return { bg: 'from-emerald-900 to-teal-900', border: 'border-emerald-500/30', iconBg: 'bg-emerald-500', text: 'text-emerald-100' };
        if (divId.includes('IT')) return { bg: 'from-slate-800 to-gray-800', border: 'border-slate-500/30', iconBg: 'bg-slate-500', text: 'text-slate-200' };
        if (divId.includes('Administrasi')) return { bg: 'from-orange-900 to-amber-900', border: 'border-orange-500/30', iconBg: 'bg-orange-500', text: 'text-orange-100' };
        return { bg: 'from-gray-800 to-gray-900', border: 'border-white/10', iconBg: 'bg-gray-600', text: 'text-gray-200' };
    };

    const handleTaskClick = (task: Task) => {
        setSelectedTask(task as any);
    };

    const renderKanbanView = () => (
        <div className="flex gap-6 pb-6 overflow-x-auto min-h-0 h-full items-start px-8 snap-x">
            {displayedDivisions.map((div: DivisionData) => {
                const divTools = filteredTools.filter((t: Tool) => t.divisionId === div.id).slice(0, 8);
                const divTasks = div.tasks.filter(t => !t.isCompleted);
                const theme = getDivisionTheme(div.id);

                return (
                    <div key={div.id} className="w-[400px] min-w-[400px] glass-card rounded-3xl flex flex-col h-full max-h-full border border-white/5 bg-[#0b1120]/60 shrink-0 snap-center shadow-2xl shadow-black/20 overflow-hidden">
                        <div className={`p-5 border-b ${theme.border} bg-gradient-to-br ${theme.bg} flex items-center justify-between shrink-0 relative overflow-hidden`}>
