                                                <div className="flex items-center gap-3 min-w-0"><div className={`w-6 h-6 rounded-md flex items-center justify-center ${tool.color || 'bg-gray-700'} text-white shadow-sm shrink-0`}><Icon name={tool.icon || 'Link'} size={12} /></div><span className="text-sm font-semibold text-gray-300 group-hover:text-white truncate">{tool.name}</span></div>
                                                <Icon name="ChevronRight" size={14} className="text-gray-600 group-hover:text-white transition-colors opacity-50 group-hover:opacity-100" />
                                            </button>
                                        </div>
                                    ))}
                                    {divTools.length === 0 && <p className="text-[10px] text-gray-600 italic pl-2 py-1">No tools pinned.</p>}
                                </div>
                            </div>
                            <div className="h-px bg-gradient-to-r from-transparent via-white/10 to-transparent w-full"></div>
                            <div className="space-y-4">
                                <div className="flex items-center justify-between"><h4 className="text-[10px] font-bold text-gray-500 uppercase tracking-widest flex items-center gap-2"><Icon name="CheckSquare" size={12}/> Tasks Queue</h4><div className="flex items-center gap-2"><button onClick={() => handleQuickAddTask(div.id)} className="flex items-center gap-1.5 px-2 py-1 rounded-lg bg-brand-500/10 hover:bg-brand-500/20 text-brand-400 hover:text-brand-300 transition-colors text-[10px] font-bold uppercase"><Icon name="Plus" size={12} /> Add</button></div></div>
                                <div className="flex overflow-x-auto gap-4 pb-4 snap-x custom-scrollbar -mx-2 px-2">
                                    {divTasks.length === 0 && (<div className="w-full py-8 text-center text-gray-600 text-xs italic border border-dashed border-white/10 rounded-xl bg-white/5 mx-2">No active tasks</div>)}
                                    {divTasks.map(task => {
                                        const subtasks = task.subtasks || [];
                                        const completedSub = subtasks.filter(s => s.isCompleted).length;

                                        return (
                                            <div key={task.id} className="min-w-[260px] w-[260px] snap-start" onClick={() => handleTaskClick(task)}>
                                                <div className="h-full bg-[#1e293b]/40 hover:bg-[#1e293b]/80 border border-white/5 hover:border-white/10 rounded-2xl p-4 transition-all duration-300 flex flex-col gap-3 group relative overflow-hidden cursor-pointer">
                                                    <div className="flex justify-between items-start">
                                                        <span className={`text-[10px] font-bold px-2 py-0.5 rounded border uppercase tracking-wider ${task.priority === 'high' ? 'text-red-300 bg-red-500/10 border-red-500/20' : 'text-blue-300 bg-blue-500/10 border-blue-500/20'}`}>{task.priority}</span>
                                                        {subtasks.length > 0 && <span className="text-[10px] text-gray-400 flex items-center gap-1 bg-white/5 px-1.5 py-0.5 rounded border border-white/5"><Icon name={completedSub === subtasks.length ? "CheckCircle2" : "ListChecks"} size={10} className={completedSub === subtasks.length ? "text-green-400" : ""}/> {completedSub}/{subtasks.length}</span>}
                                                    </div>
                                                    <p className="text-sm font-medium text-gray-200 line-clamp-3 leading-relaxed group-hover:text-white transition-colors">{task.title}</p>

                                                    {/* Attachment Indicator */}
                                                    {task.attachmentUrl && <div className="flex items-center gap-1 text-[10px] text-blue-400 bg-blue-500/10 px-1.5 py-0.5 rounded border border-blue-500/20 w-fit"><Icon name="Paperclip" size={10}/> Document Attached</div>}

                                                    <div className="mt-auto pt-3 border-t border-white/5 flex justify-between items-center opacity-70 group-hover:opacity-100 transition-opacity">
                                                        <button onClick={(e) => { e.stopPropagation(); onToggleTask(div.id, task.id); }} className="w-8 h-8 rounded-lg bg-black/40 hover:bg-emerald-500/20 text-gray-400 hover:text-emerald-400 flex items-center justify-center transition-colors" title="Complete"><Icon name="Check" size={16} /></button>
                                                        <div className="flex gap-1">
                                                            <button onClick={(e) => { e.stopPropagation(); handleWhatsApp(task); }} className="p-2 text-gray-500 hover:text-green-400 hover:bg-white/5 rounded-lg"><Icon name="MessageCircle" size={16}/></button>
                                                            <button onClick={(e) => { e.stopPropagation(); onDeleteTask(div.id, task.id); }} className="p-2 text-gray-500 hover:text-red-400 hover:bg-white/5 rounded-lg"><Icon name="Trash2" size={16}/></button>
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                        );
                                    })}
                                    <div className="min-w-[1px]"></div> 
                                </div>
                            </div>
                        </div>
                    </div>
                );
            })}
        </div>
    );

    return (
        <div className="h-full flex flex-col overflow-y-auto overflow-x-hidden md:overflow-hidden bg-[radial-gradient(ellipse_at_top_right,_var(--tw-gradient-stops))] from-[#020617] via-[#0f172a] to-[#172554]">
            <TaskTicker tasks={tickerTasks} onTaskClick={() => openPanel('tasks')} />
            <div className="flex items-center justify-between px-6 py-4 shrink-0 z-20">
                <div className="flex items-center gap-4 w-full md:w-auto">
                    <h1 className="md:hidden text-xl font-bold text-white tracking-tight">STIS-DU</h1>
                    <div className="hidden md:block relative group w-64 xl:w-96">
                        <Icon name="Search" className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500" size={16} />
                        <input type="text" placeholder={t.dashboard.searchPlaceholder} value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} className="w-full pl-10 pr-4 py-2.5 bg-white/5 border border-white/10 rounded-xl text-xs text-white placeholder-gray-600 shadow-lg backdrop-blur-sm transition-all" />
                    </div>
                    <div className="hidden md:flex bg-black/30 p-1 rounded-lg border border-white/10">
                        <button onClick={() => setDashboardView('grid')} className={`p-2 rounded-md transition-all ${dashboardView === 'grid' ? 'bg-white/10 text-brand-400 shadow-sm' : 'text-gray-500 hover:text-white'}`} title="Grid View"><Icon name="LayoutGrid" size={18} /></button>
                        <button onClick={() => setDashboardView('kanban')} className={`p-2 rounded-md transition-all ${dashboardView === 'kanban' ? 'bg-white/10 text-brand-400 shadow-sm' : 'text-gray-500 hover:text-white'}`} title="Kanban Command Center"><Icon name="KanbanSquare" size={18} /></button>
                    </div>
                </div>
                <div className="flex items-center gap-4">
                    <button onClick={() => openPanel('discussion')} className="p-2 bg-white/5 rounded-full relative hover:bg-white/10 transition-colors"><Icon name="Bell" size={18} className="text-gray-400"/>{unreadAnnouncements > 0 && <div className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full border border-black animate-pulse"></div>}</button>
                    <div className="hidden md:flex items-center gap-3 pl-4 border-l border-white/10"><div className="text-right"><p className="text-xs font-bold text-white">{user.name}</p><p className="text-[10px] text-gray-500">{user.role}</p></div><div className="w-9 h-9 rounded-full bg-gradient-to-r from-pink-500 to-rose-500 flex items-center justify-center text-white font-bold shadow-md ring-2 ring-white/10">{user.name.charAt(0)}</div></div>
                </div>
            </div>
            <div className="flex-1 flex gap-6 px-4 md:px-8 pb-20 md:pb-8 min-h-0 relative">
                <div className="flex-1 flex flex-col min-h-0 max-w-7xl mx-auto w-full">
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6 shrink-0">
                        <ActionZoneCard label={todayAttendance ? "Clocked In" : t.dashboard.attendance} subLabel={todayAttendance ? new Date(todayAttendance.checkInTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) : undefined} icon={todayAttendance ? "Clock" : "Fingerprint"} color={todayAttendance ? "emerald" : "slate"} isActive={!!todayAttendance} onClick={onOpenAttendance} />
                        <ActionZoneCard label={t.dashboard.chat} icon="MessageSquare" color="violet" onClick={() => openPanel('discussion')} />
                        <ActionZoneCard label={t.dashboard.tasks} icon="CheckSquare" color="amber" onClick={() => openPanel('tasks')} />
                        <ActionZoneCard label={t.dashboard.profile} icon="User" color="blue" onClick={onOpenProfile} />
                    </div>
                    {dashboardView === 'grid' && (<SummaryBar toolCount={tools.length} labelOverview={user.role === UserRole.ADMIN ? t.dashboard.systemOverview : `${DIVISIONS.find(d => d.id === user.division)?.name || 'My'} Workspace`} labelTools={t.dashboard.tools} labelOnline={t.dashboard.online} />)}
                    <div className="flex-1 min-h-0 flex flex-col">
                        {dashboardView === 'kanban' ? renderKanbanView() : (
                            <div className="flex-1 overflow-y-auto custom-scrollbar pr-2 pb-10">
                                <div className="md:hidden flex flex-col gap-2">{displayedDivisions.map((div: DivisionData) => <DivisionAccordion key={div.id} division={div} tools={filteredTools.filter((t: Tool) => t.divisionId === div.id)} onToolClick={handleToolClick} onContextMenu={onContextMenu} />)}</div>
                                <div className={`hidden md:grid gap-6 ${displayedDivisions.length === 1 ? 'grid-cols-1' : 'md:grid-cols-2 lg:grid-cols-3'}`}>
                                    {displayedDivisions.map((div: DivisionData) => (
                                        <div key={div.id} className="h-full"><GlassDivisionCard division={div} tools={filteredTools.filter((t: Tool) => t.divisionId === div.id)} onViewAll={() => navigate(`/division/${div.id}`)} onToolClick={handleToolClick} onContextMenu={onContextMenu} onSelect={onSelect} onSmartAdd={() => setSmartAddContext(div.id)} onMirrorDrop={handleMirrorTool} isSelectionMode={isSelectionMode} selectedIds={selectedIds} viewLabel={t.dashboard.viewDivision} canAdd={hasEditPermission(div.id)} /></div>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            </div>

            <CollaborationPanel isOpen={isPanelOpen} onClose={() => setIsPanelOpen(false)} user={user} initialTab={panelTab} divisions={dashboardDivisions} onAddTask={onAddTask} onToggleTask={onToggleTask} onDeleteTask={onDeleteTask} onUpdateTask={onUpdateTask} announcements={announcements} messages={messages} onSendMessage={onSendMessage} activeChannel={activeChannel} onChangeChannel={onChangeChannel} groups={groups} />

            {selectedTask && (
                <TaskDetailView 
                    task={selectedTask} 
                    isOpen={!!selectedTask} 
                    onClose={() => setSelectedTask(null)} 
                    onToggle={() => onToggleTask(selectedTask.divId || selectedTask.originDivisionId, selectedTask.id)} 
                    onDelete={() => { onDeleteTask(selectedTask.divId || selectedTask.originDivisionId, selectedTask.id); setSelectedTask(null); }} 
                    onUpdate={(updates) => onUpdateTask && onUpdateTask(selectedTask.divId || selectedTask.originDivisionId, selectedTask.id, updates)} 
                />
            )}

            <div className="h-10"></div>
        </div>
    );
};
